parameters.jsCode:
// Aggregate Service responses · AUGMENTED 2026-06-27 (dispatch multi-source) ·
// Tarea 3 · graceful degradation + discovery_package.sources[].
// Mirror of aggregateDiscoverySources() in src/lib/onboarding-discovery/url-classifier.ts.
//
// A failed actor is marked status:'failed' and the run CONTINUES · one down
// source NEVER aborts the whole discovery. The sources[] array (what ran ·
// status · count · trust_level) is surfaced for Camino III + the brain write.

const items = $input.all();
const summary = { total_calls: items.length, successes: 0, errors: 0, skipped_gate: 0, by_function: {} };
const sources = [];
let okCount = 0, failedCount = 0, totalResults = 0;

for (const it of items) {
  const r = it.json || {};
  const fn = r.apify_function || 'unknown';
  summary.by_function[fn] = (summary.by_function[fn] || 0) + 1;

  if (r.status === 'skipped' || r.skip_reason) {
    summary.skipped_gate++;
    continue; // gate skip-markers are not a source success/failure
  }

  const failed = r.success === false || !!r.error;
  const count =
    typeof r.result_count === 'number' ? r.result_count
    : Array.isArray(r.results) ? r.results.length
    : typeof r.count === 'number' ? r.count : 0;

  if (failed) {
    summary.errors++;
    failedCount++;
    sources.push({
      apify_function: fn, status: 'failed', count: 0,
      trust_level: r.trust_level || 'untrusted',
      source: r.source || 'apify_scrape',
      error: (r.error && (r.error.message || String(r.error))) || 'actor failed',
    });
  } else {
    summary.successes++;
    okCount++;
    totalResults += count;
    sources.push({
      apify_function: fn, status: 'ok', count: count,
      trust_level: r.trust_level || 'untrusted',
      source: r.source || 'apify_scrape',
    });
  }
}

return [{ json: {
  scope: 'onboarding_e2e',
  destination_table: 'client_competitive_landscape',
  summary,
  // Tarea 3 · top-level sources[] · merged into discovery_package downstream.
  sources,
  sources_summary: { ok_count: okCount, failed_count: failedCount, total_results: totalResults },
  ran_at: new Date().toISOString(),
} }];

// Model B · DISPATCH-ÚNICO guard
// Rechaza runs que no vengan via sala dispatch.
// Fix Ola 2 2026-06-05 · variable scoping · return reusa `...body` (que ya incluye los _ underscores)
const body = $input.first().json.body || $input.first().json;
if (!body._sala_correlation_id || !body._journey_id) {
  throw new Error(
    'DISPATCH_REJECTED · Model B canon · este worker SOLO acepta '+
    'dispatch via sala. Faltan _sala_correlation_id + _journey_id ' +
    'en body. Scoped al run · no corta workflow.'
  );
}
// Pasa el body completo (incluye _sala_correlation_id + _journey_id + resto)
return [{ json: { ...body, _modelb_guard: 'passed' } }];

// Canon shape for Master Journey ugK3QrxkWq22Bly5 sub-workflow input.
// parse-validate-request (entry) reads $input.first().json.body.
// Required: journey (one of ACQUIRE|ONBOARD|PRODUCE|ALWAYS_ON|REVIEW)
//           client_id (string · except ACQUIRE)
//           trigger_type (string · 'manual' default)
//           params (object · free-form context)
// Fix root · Sprint 7 C5 cutover converted httpRequest→executeWorkflow
// but never wrapped payload as { body: {...} } per webhook entry shape.

const deal = $('Validate Deal Data').first().json;
const cascade = $input.first().json;

return [{
  json: {
    body: {
      journey: 'ONBOARD',
      client_id: deal.client_id,
      trigger_type: 'deal-won-onboarding',
      params: {
        client_name: deal.client_name || null,
        website: deal.website || null,
        industry: deal.industry || null,
        sala_correlation_id: deal._sala_correlation_id || null,
        journey_id: deal._journey_id || null,
        cascade_response: (cascade && typeof cascade === 'object') ? cascade : null,
        upstream_workflow_id: $workflow.id,
        upstream_execution_id: $execution.id,
      },
    },
  },
}];

// Canon · unwrap Vercel callback envelope (PR #185 contract) into the same shape
// the synchronous /api/agents/run-sdk used to return. Name preserved to keep
// existing references ($('Call Onboarding Specialist: Auto-Discovery').item.json.*)
// resolving transparently · zero text-edits across downstream consumer nodes.
//
// Vercel callback body shape · { status, agent_slug, client_id, result: <agentResult> }
// where agentResult mirrors sync-mode response body { response, result, discovery_output, ... }.
// If callback already arrives unwrapped (no `result` envelope) · pass through.

const cb = $input.first().json;
const unwrapped = (cb && typeof cb === 'object' && 'result' in cb) ? cb.result : cb;
return [{ json: unwrapped }];

// Synthesis Staging · Fase 3 · spec 5-fases CC#4 2026-06-09
// Consolida en memoria: agent output + Apify results → staging_package
// NO hace INSERT/UPDATE a ninguna tabla.

const discoveryItem = $('Confirm barato · competitor list').first().json;
const apifyAggregate = $('[APIFY-WIRE] Aggregate Service responses (onboarding_e2e)').first().json;
const dealData = $('Validate Deal Data').first().json;

const discoveryPkg = discoveryItem.discovery_package || {};
const apifyResults = apifyAggregate.results || apifyAggregate.apify_results || [];

