};

// competitive_analysis_draft
const competitiveAnalysisDraft = {
  competitors: discoveryPkg.competitors || [],
  scrape_targets_count: discoveryPkg.scrape_targets ? discoveryPkg.scrape_targets.length : 0,
  apify_results: apifyResults,
  landscape_summary: discoveryPkg.discovery_summary || "",
  draft_status: "pre_gate"
};

const stagingPackage = {
  brand_book_draft: brandBookDraft,
  icp_draft: icpDraft,
  competitive_analysis_draft: competitiveAnalysisDraft,
  evidence_sources: ["onboarding-specialist", "apify"],
