const r = $input.first().json; const body = (r && r.body) ? r.body : r;
let txt = ''; if (body && typeof body === 'object') txt = body.response || body.output_summary || ''; else if (typeof body === 'string') txt = body;
let veredicto = 'observar', razones = ['default_observar_no_parseable'], confianza = 0;
try { const m = (txt || '').match(/\{[\s\S]*\}/); if (m) { const j = JSON.parse(m[0]);
  const v = String(j.veredicto || j.verdict || '').toLowerCase();
  veredicto = (v === 'confirmar' || v === 'confirm') ? 'confirmar' : 'observar';
  razones = Array.isArray(j.razones) ? j.razones : (Array.isArray(j.reasons) ? j.reasons : []);
  confianza = typeof j.confianza === 'number' ? j.confianza : (typeof j.confidence === 'number' ? j.confidence : 0);
} } catch (e) { veredicto = 'observar'; razones = ['parse_error: ' + (e.message || String(e))]; }
return [{ json: { veredicto, razones, confianza,
  client_id: $('Validate Deal Data').item.json.client_id,
  client_name: $('Validate Deal Data').item.json.client_name,
  competitor_list: $('Confirm barato · competitor list').item.json,
  _verdict_raw: (txt || '').slice(0, 800) } }];

